import{_ as a,c as o,o as e,a1 as d}from"./chunks/framework.DDNAyvCW.js";const l="/assets/chattoai1.IWN0_x5k.png",i="/assets/chattoai2.BhLwv8Co.png",q=JSON.parse('{"title":"Chat to AI","description":"","frontmatter":{},"headers":[],"relativePath":"docs/terminal/chattoai/index.md","filePath":"docs/terminal/chattoai/index.md"}'),r={name:"docs/terminal/chattoai/index.md"};function c(n,t,h,s,u,m){return e(),o("div",null,t[0]||(t[0]=[d('<h1 id="chat-to-ai" tabindex="-1">Chat to AI <a class="header-anchor" href="#chat-to-ai" aria-label="Permalink to &quot;Chat to AI&quot;">​</a></h1><p>Chat to AI 让您在终端中直接与 AI 交互，生成命令、排查问题并规划复杂任务。</p><p>Chaterm 提供两种不同的 AI 交互模式，根据您的任务选择合适的方式：</p><table tabindex="0"><thead><tr><th>模式</th><th>快捷键</th><th>适用场景</th></tr></thead><tbody><tr><td>AI 命令对话框</td><td><code>Cmd + K</code> / <code>Ctrl + K</code></td><td>快速生成单个命令</td></tr><tr><td>AI 侧边栏</td><td><code>Cmd + L</code> / <code>Ctrl + L</code></td><td>需要上下文和多轮对话的复杂任务</td></tr></tbody></table><h2 id="模式一-ai-命令对话框-cmd-k-ctrl-k" tabindex="-1">模式一：AI 命令对话框（<code>Cmd + K</code> / <code>Ctrl + K</code>） <a class="header-anchor" href="#模式一-ai-命令对话框-cmd-k-ctrl-k" aria-label="Permalink to &quot;模式一：AI 命令对话框（`Cmd + K` / `Ctrl + K`）&quot;">​</a></h2><p>轻量级弹窗，将自然语言描述转换为可直接运行的命令。当您知道想做什么但不确定具体语法时使用。</p><p><img src="'+l+'" alt=""></p><h3 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to &quot;操作步骤&quot;">​</a></h3><ol><li>在终端中按 <code>Cmd + K</code>（macOS）或 <code>Ctrl + K</code>（Windows/Linux）。</li><li>用自然语言输入您想要完成的操作。</li><li>AI 生成对应的命令。</li><li>检查命令后，按回车键将其插入终端。</li></ol><h3 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h3><ul><li>需要执行某个命令但记不住参数或语法。</li><li>想要执行单个简单的操作。</li><li>查询特定工具的使用方法。</li></ul><h3 id="示例" tabindex="-1">示例 <a class="header-anchor" href="#示例" aria-label="Permalink to &quot;示例&quot;">​</a></h3><table tabindex="0"><thead><tr><th>您输入的内容</th><th>AI 生成的命令</th></tr></thead><tbody><tr><td>&quot;查找所有大于 100MB 的 <code>.log</code> 文件&quot;</td><td><code>find / -name &quot;*.log&quot; -size +100M</code></td></tr><tr><td>&quot;按大小排序显示磁盘使用情况&quot;</td><td><code>du -sh /* | sort -rh</code></td></tr><tr><td>&quot;重启 nginx 服务&quot;</td><td><code>sudo systemctl restart nginx</code></td></tr><tr><td>&quot;压缩 <code>/var/log</code> 目录&quot;</td><td><code>tar -czf /tmp/var-log-backup.tar.gz /var/log</code></td></tr></tbody></table><h2 id="模式二-ai-侧边栏-cmd-l-ctrl-l" tabindex="-1">模式二：AI 侧边栏（<code>Cmd + L</code> / <code>Ctrl + L</code>） <a class="header-anchor" href="#模式二-ai-侧边栏-cmd-l-ctrl-l" aria-label="Permalink to &quot;模式二：AI 侧边栏（`Cmd + L` / `Ctrl + L`）&quot;">​</a></h2><p>常驻侧边栏，能够读取终端的上下文 -- 输出历史、工作目录和环境信息 -- 并支持与 AI 进行多轮对话。适用于需要规划、排查或迭代的场景。</p><p><img src="'+i+'" alt=""></p><h3 id="操作步骤-1" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-1" aria-label="Permalink to &quot;操作步骤&quot;">​</a></h3><ol><li>在终端中按 <code>Cmd + L</code>（macOS）或 <code>Ctrl + L</code>（Windows/Linux）。</li><li>侧边栏打开并自动捕获当前终端上下文。</li><li>描述您的任务或提出问题。</li><li>AI 分析上下文并给出建议或命令。</li><li>继续对话以完善方案，然后逐步执行命令。</li></ol><h3 id="ai-读取的上下文" tabindex="-1">AI 读取的上下文 <a class="header-anchor" href="#ai-读取的上下文" aria-label="Permalink to &quot;AI 读取的上下文&quot;">​</a></h3><ul><li>当前终端输出和滚动历史记录。</li><li>当前工作目录。</li><li>终端会话环境信息。</li></ul><h3 id="适用场景-1" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景-1" aria-label="Permalink to &quot;适用场景&quot;">​</a></h3><ul><li>任务需要多个步骤（例如：部署应用程序）。</li><li>需要排查终端输出中可见的错误。</li><li>想在执行命令前讨论不同方案的优劣。</li><li>需要 AI 理解会话中刚发生的事情。</li></ul><h3 id="示例-排查服务启动失败" tabindex="-1">示例：排查服务启动失败 <a class="header-anchor" href="#示例-排查服务启动失败" aria-label="Permalink to &quot;示例：排查服务启动失败&quot;">​</a></h3><p><strong>之前（手动操作）：</strong> 您在终端中看到 <code>nginx.service: Failed</code>。您手动运行 <code>journalctl</code>，查看日志，编辑配置文件，然后重启 -- 一路靠猜测。</p><p><strong>之后（使用 AI 侧边栏）：</strong></p><ol><li>按 <code>Cmd + L</code> 打开侧边栏。AI 自动读取错误输出。</li><li>输入：&quot;nginx 为什么启动失败了？&quot;</li><li>AI 读取终端输出，识别配置语法错误，并建议修复方法。</li><li>您应用修复后问 AI：&quot;检查一下 nginx 配置现在是否有效。&quot;</li><li>AI 生成 <code>nginx -t</code>，您运行后 AI 确认成功。</li></ol><h2 id="快捷键" tabindex="-1">快捷键 <a class="header-anchor" href="#快捷键" aria-label="Permalink to &quot;快捷键&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>macOS</th><th>Windows/Linux</th></tr></thead><tbody><tr><td>打开 AI 命令对话框</td><td><code>Cmd + K</code></td><td><code>Ctrl + K</code></td></tr><tr><td>打开 / 切换 AI 侧边栏</td><td><code>Cmd + L</code></td><td><code>Ctrl + L</code></td></tr></tbody></table><h2 id="使用技巧" tabindex="-1">使用技巧 <a class="header-anchor" href="#使用技巧" aria-label="Permalink to &quot;使用技巧&quot;">​</a></h2><ul><li><strong>描述要具体。</strong> 与其说&quot;修复这个&quot;，不如说&quot;nginx 配置第 42 行有语法错误 -- 请建议修复方法。&quot;</li><li><strong>复杂任务使用侧边栏。</strong> 让 AI 规划步骤，然后逐一执行。</li><li><strong>保存有用的命令。</strong> AI 生成的常用命令可以保存为<a href="/docs/terminal/snippets/">快捷命令</a>，以便日后一键执行。</li><li><strong>执行前务必检查。</strong> 始终在运行 AI 生成的命令前仔细阅读，特别是在生产服务器上。</li></ul><div class="warning custom-block"><p class="custom-block-title">安全提示</p><ul><li>不要在未经检查的情况下执行可能造成数据丢失的 AI 生成命令。</li><li>对于敏感操作，务必手动确认。</li><li>在生产环境运行前，先在测试环境中验证有风险的命令。</li></ul></div><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/docs/ai/dialogs/">AI 对话</a> -- AI 对话配置和功能的更多详情。</li><li><a href="/docs/terminal/snippets/">快捷命令</a> -- 保存和复用 AI 生成的命令。</li></ul>',33)]))}const p=a(r,[["render",c]]);export{q as __pageData,p as default};
